function addSkuCategories(n){for(var i,t=0;t<n.length;t++)i=new Option(n[t].category,n[t].attribute,!1,!1),$("#sku-category").append(i).trigger("change")}function addSkuColors(n){for(var i,t=0;t<n.length;t++)i=new Option(n[t].color,n[t].attribute,!1,!1),$("#sku-color").append(i).trigger("change")}function addSkuUnitOfMeasure(n){for(var i,t=0;t<n.length;t++)i=new Option(n[t].unitOfMeasure,n[t].attribute,!1,!1),$("#sku-UOM").append(i).trigger("change")}function buildSkuItem(){$("#full-sku").val($("#sku-category").select2().val()+$("#sku-UOM").select2().val()+$("#sku-color").select2().val());$("#sku-set-number").val()>1&&$("#full-sku").val($("#full-sku").val()+"SO"+$("#sku-set-number").val())}